{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyN0EAMfoJgYWHMaqz7d/GbZ"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"EKBVyVcfoXrP"},"outputs":[],"source":["-- Overall air quality ranking by district\n","SELECT stationname,\n","       AVG(CAST(khaivalue AS DOUBLE)) AS avg_khai, --KHAI,통합대기환경지수\n","       AVG(CAST(pm25value AS DOUBLE)) AS avg_pm25,\n","       AVG(CAST(pm10value AS DOUBLE)) AS avg_pm10\n","FROM air_quality\n","WHERE khaivalue != '-'\n","  AND pm25value != '-'\n","  AND pm10value != '-'\n","GROUP BY stationname\n","ORDER BY avg_khai DESC;"]}]}